import json, os
DEMOS_DIR = {{recording_output.path}}
ROBOT_PATH = {{primary_robot.path}}
N_DEMOS = {{recording_output.n_demos}}
FREQUENCY_HZ = {{recording_output.frequency_hz}}
DEVICE = {{input_device.device}}
SESSION_SUMMARY_FILE = os.path.join(DEMOS_DIR, "session_summary.json")
RESULT_FILE = "/tmp/groot_teleop_demo_record_result.json"
os.makedirs(DEMOS_DIR, exist_ok=True)
create_prim(prim_path="/World/DomeLight", prim_type="DomeLight")
set_attribute(prim_path="/World/DomeLight", attr_name="inputs:intensity", value=1000.0)
create_prim(prim_path="/World/Ground", prim_type="Cube", position=[0, 0, -0.5], scale=[20, 20, 1])
apply_api_schema(prim_path="/World/Ground", schema_name="PhysicsCollisionAPI")
create_prim(prim_path="/World/Table", prim_type="Cube", position=[0, 0, 0.375], scale=[0.5, 0.4, 0.375])
apply_api_schema(prim_path="/World/Table", schema_name="PhysicsCollisionAPI")
create_prim(prim_path={{demonstration_target.path}}, prim_type="Cube", position={{demonstration_target.position}}, scale={{demonstration_target.scale}})
apply_api_schema(prim_path={{demonstration_target.path}}, schema_name="PhysicsCollisionAPI")
apply_api_schema(prim_path={{demonstration_target.path}}, schema_name="PhysicsRigidBodyAPI")
create_prim(prim_path={{demonstration_destination.path}}, prim_type="Cube", position={{demonstration_destination.position}}, scale={{demonstration_destination.scale}})
apply_api_schema(prim_path={{demonstration_destination.path}}, schema_name="PhysicsCollisionAPI")
set_physics_scene_config(config={"enable_gpu_dynamics": False, "broadphase_type": "MBP"})
robot_wizard(robot_name={{primary_robot.class}}, dest_path=ROBOT_PATH, position={{primary_robot.position}}, orientation={{primary_robot.orientation}})
sim_control(action="play")
sim_control(action="step", step_count=30)
hw_report = check_teleop_hardware(device=DEVICE)
hw_ok = isinstance(hw_report, dict) and hw_report.get("supported", True) is not False
configure_teleop_mapping(robot_path=ROBOT_PATH, device_axes={{input_device.axes}}, joint_names=["panda_joint1", "panda_joint2", "panda_joint3", "panda_joint4", "panda_joint5", "panda_joint6", "panda_joint7"], gains={{input_device.gains}})
start_teleop_session(robot_path=ROBOT_PATH, input_device=DEVICE, stream_quality="medium")
recorded_files = []
for i in range(N_DEMOS):
    demo_path = os.path.join(DEMOS_DIR, f"demo_{i:03d}.hdf5")
    try:
        record_teleop_demo(output_path=demo_path, robot_path=ROBOT_PATH, frequency_hz=FREQUENCY_HZ)
        sim_control(action="step", step_count=60)
        if os.path.exists(demo_path):
            recorded_files.append(demo_path)
    except Exception as exc:
        print(f"[ERR] record demo {i}: {exc}")
all_valid = True
for demo_path in recorded_files:
    try:
        v = validate_teleop_demo(hdf5_path=demo_path)
        if isinstance(v, dict) and v.get("valid", True) is False:
            all_valid = False
    except Exception:
        all_valid = False
per_demo = {}
for demo_path in recorded_files:
    try:
        per_demo[demo_path] = summarize_teleop_session(hdf5_path=demo_path, fps=FREQUENCY_HZ)
    except Exception as exc:
        per_demo[demo_path] = {"error": str(exc)}
session_summary = {"demo_count": len(recorded_files), "target_demo_count": N_DEMOS, "all_valid": all_valid, "per_demo": per_demo}
with open(SESSION_SUMMARY_FILE, "w") as f:
    json.dump(session_summary, f, indent=2, default=str)
try:
    stop_teleop_session()
except Exception as exc:
    print(f"[WARN] stop_teleop_session: {exc}")
sim_control(action="stop")
session_ok = len(recorded_files) == N_DEMOS and all_valid
with open(RESULT_FILE, "w") as f:
    json.dump({"session_ok": session_ok, "files_on_disk": len(recorded_files), "target_demo_count": N_DEMOS, "all_valid": all_valid, "session_summary_file": SESSION_SUMMARY_FILE}, f, indent=2)
get_console_errors(last_n=10, min_level="error")
assert os.path.exists(RESULT_FILE), "Result file must exist regardless of session_ok"
